// usePersistedShared.ts
import {useEffect, useRef} from 'react';
import {useSharedValue, useAnimatedReaction, runOnJS} from 'react-native-reanimated';
import {MMKV} from 'react-native-mmkv';
const storage = new MMKV();
export function usePersistedShared(key: string, initial: number) { const v = useSharedValue(storage.getNumber(key) ?? initial); const t = useRef<any>(); useAnimatedReaction(() => v.value, (cur) => { runOnJS((val: number) => { clearTimeout(t.current); t.current = setTimeout(() => storage.set(key, val), 400); })(cur); }); return v; }

