export function JiggleItem({editing, children}: {editing: boolean; children: React.ReactNode}) { const r = useSharedValue(0); React.useEffect(() => { if (editing) r.value = withRepeat(withSequence(withTiming(1, {duration: 100}), withTiming(-1, {duration: 100})), -1, true); else { cancelAnimation(r); r.value = 0; }}, [editing]); const style = useAnimatedStyle(() => ({transform: [{rotate: `${r.value}deg`}]})); return <Animated.View style={style}>{children}</Animated.View>; }

