// RangeSlider.tsx
import React, {useState} from 'react';
import {StyleSheet, View} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, runOnJS} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function RangeSlider({min, max, value, onChange}: {min: number; max: number; value: [number, number]; onChange: (v: [number, number]) => void}) {
  const [width, setWidth] = useState(0);
  const lo = useSharedValue(((value[0] - min) / (max - min)) * width);
  const hi = useSharedValue(((value[1] - min) / (max - min)) * width);
  const update = () => { onChange([min + (lo.value/width)*(max-min), min + (hi.value/width)*(max-min)]); };
  const loPan = Gesture.Pan().onUpdate(e => { lo.value = Math.max(0, Math.min(hi.value - 20, e.x)); runOnJS(Haptics.selectionAsync)(); }).onEnd(() => runOnJS(update)());
  const hiPan = Gesture.Pan().onUpdate(e => { hi.value = Math.max(lo.value + 20, Math.min(width, e.x)); runOnJS(Haptics.selectionAsync)(); }).onEnd(() => runOnJS(update)());
  const fillStyle = useAnimatedStyle(() => ({left: lo.value, width: hi.value - lo.value}));
  const loStyle = useAnimatedStyle(() => ({transform: [{translateX: lo.value - 14}]}));
  const hiStyle = useAnimatedStyle(() => ({transform: [{translateX: hi.value - 14}]}));
  return (<View style={s.root} onLayout={e => setWidth(e.nativeEvent.layout.width)}><View style={s.track}><Animated.View style={[s.fill, fillStyle]}/></View><GestureDetector gesture={loPan}><Animated.View style={[s.thumb, loStyle]}/></GestureDetector><GestureDetector gesture={hiPan}><Animated.View style={[s.thumb, hiStyle]}/></GestureDetector></View>);
}
const s = StyleSheet.create({root:{height:44, justifyContent:'center', position:'relative'}, track:{height:4, backgroundColor:'#2C2C2E', borderRadius:2}, fill:{position:'absolute', height:4, backgroundColor:'#0A84FF', borderRadius:2}, thumb:{position:'absolute', width:28, height:28, borderRadius:14, backgroundColor:'#fff'}});

