export function TypewriterText({text, width = 300, fontSize = 16}: {text: string; width?: number; fontSize?: number}) { const font = useFont(require('./assets/Inter-Regular.ttf'), fontSize); const idx = useSharedValue(0); useEffect(() => { idx.value = withTiming(text.length, {duration: text.length * 40, easing: Easing.linear}); }, [text]); const visibleText = useDerivedValue(() => text.slice(0, Math.floor(idx.value))); if (!font) return <View style={{height: fontSize}}/>; return (<Canvas style={{width, height: fontSize * 1.4}}><SkText x={0} y={fontSize} text={visibleText} font={font} color='#fff'/></Canvas>); }

