import React, {useState} from 'react';
import {StyleSheet, View, Pressable, Text} from 'react-native';
import {Audio} from 'expo-av';
import {Waveform} from './Waveform';
export function VoiceNote({uri, peaks, durationMs}: {uri: string; peaks: number[]; durationMs: number}) { const [pos, setPos] = useState(0); const [playing, setPlaying] = useState(false); const soundRef = React.useRef<Audio.Sound | null>(null); const toggle = async () => { if (!soundRef.current) { const {sound} = await Audio.Sound.createAsync({uri}); soundRef.current = sound; sound.setOnPlaybackStatusUpdate(s => { if (s.isLoaded) { setPos(s.positionMillis); setPlaying(s.isPlaying); }}); } if (playing) soundRef.current.pauseAsync(); else soundRef.current.playAsync(); }; return (<View style={s.row}><Pressable onPress={toggle} style={s.play}><Text style={s.icon}>{playing ? '⏸' : '▶'}</Text></Pressable><Waveform peaks={peaks} width={180} durationMs={durationMs} positionMs={pos} isPlaying={playing} onSeek={ms => soundRef.current?.setPositionAsync(ms)}/><Text style={s.dur}>{Math.round((durationMs - pos)/1000)}s</Text></View>); }
