import React from 'react';
import {StyleSheet, View} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withSpring, runOnJS} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
export function LiftOnPress({children, onCommit}: {children: React.ReactNode; onCommit: () => void}) { const lift = useSharedValue(0); const longPress = Gesture.LongPress().minDuration(350).onStart(() => { runOnJS(Haptics.impactAsync)(Haptics.ImpactFeedbackStyle.Medium); lift.value = withSpring(1, {damping: 14}); }).onEnd(() => { lift.value = withSpring(0, {damping: 16}); runOnJS(onCommit)(); }); const style = useAnimatedStyle(() => ({transform: [{scale: 1 + lift.value * 0.05}], shadowOpacity: lift.value * 0.3, elevation: lift.value * 12})); return (<GestureDetector gesture={longPress}><Animated.View style={[s.wrap, style]}>{children}</Animated.View></GestureDetector>); }
