export function GradientText({text, fontSize = 32}: {text: string; fontSize?: number}) { const font = useFont(require('./assets/Inter-Bold.ttf'), fontSize); const t = useSharedValue(0); React.useEffect(() => { t.value = withRepeat(withTiming(1, {duration: 3000, easing: Easing.linear}), -1, false); }, []); const grad = useDerivedValue(() => ({start: vec(-200 + t.value * 400, 0), end: vec(t.value * 400, 0)})); if (!font) return <View style={{height: fontSize * 1.4}}/>; return (<Canvas style={{width: 300, height: fontSize * 1.4}}><SkText x={0} y={fontSize} text={text} font={font}><LinearGradient start={grad.value.start} end={grad.value.end} colors={['#FF3B5C', '#FFCC00', '#0A84FF']}/></SkText></Canvas>); }

